// Function to extract data from localStorage
function getLocalStorageData(keyPrefix) {
  const localStorageData = {};

  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key && !key.startsWith(keyPrefix)) { // Ignore keys starting with the prefix
      const value = localStorage.getItem(key);
      if (value !== null) { // Handle cases where the key might have been deleted
        localStorageData[key] = value;
      }
    }
  }

  return localStorageData;
}

